import { withDb } from "./db.mjs";

const riskScoreCheck = `
        NOT (doc ? 'riskScore')
        OR (
          jsonb_typeof(doc->'riskScore') = 'number'
          AND (doc->>'riskScore') ~ '^[0-9]+$'
          AND (doc->>'riskScore')::int BETWEEN 0 AND 100
        )
      `;

export async function ensureSchema(client) {
  await client.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc        JSONB NOT NULL,
      CONSTRAINT accounts_doc_key_match CHECK (doc->>'accountId' = account_id),
      CONSTRAINT accounts_doc_risk_score_check CHECK (${riskScoreCheck})
    )
  `);
  await client.query(`
    DO $$
    BEGIN
      IF NOT EXISTS (
        SELECT 1
        FROM pg_constraint
        WHERE conname = 'accounts_doc_risk_score_check'
          AND conrelid = 'accounts'::regclass
      ) THEN
        ALTER TABLE accounts
          ADD CONSTRAINT accounts_doc_risk_score_check CHECK (${riskScoreCheck});
      END IF;
    END $$;
  `);
  await client.query('CREATE INDEX IF NOT EXISTS idx_accounts_doc_gin ON accounts USING GIN (doc jsonb_path_ops)');
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}

